scwin.sbm_getInitPage_submitdone = async function (e) {
  let ret = e.responseJSON;
  let initFlag = false;
  try {
    if (ret.length > 0) {
      for (let idx = 0; idx < ret.length; idx++) {
        let actPgmId = ret[idx].actPgmId;
        let actPgmScrPath = ret[idx].actPgmScrPath;
        let menuNm = ret[idx].menuNm;
        let menuId = ret[idx].menuId;
        let pgmNm = ret[idx].pgmNm;
        let prefix = "/ui";
        if (actPgmScrPath && actPgmId) {
          prefix += actPgmScrPath.substring(0, 1) !== "/" ? "/" : "";
          if (actPgmScrPath.indexOf("/sample") > -1 || actPgmScrPath.indexOf("/pub") > -1 || actPgmScrPath.indexOf("/ui") > -1) {
            prefix = "";
          }
          let src = prefix + actPgmScrPath + actPgmId;
          src = src.replace(/.jsp/g, ".xml");
          initFlag = true;
          await $c.win.openMenu($p, menuNm, src, actPgmId, null, {
            pgmNm: pgmNm,
            menuId: menuId
          });
        }
      }
    } else {
      if (!initFlag) {
        // 시작 화면이 등록되어 있으면 환경설정 화면 호출
        $c.win.openMenu($p, "환경설정(Tab/m)", "/ui/cm/bc/comnmgnt/usermgnt/zz_620_01_00b.xml", "zz_620_01_00b.jsp", {
          init: "Y"
        });
      }
    }
  } catch (e) {
    console.log(e);
  }
};
